mapper.select:
SELECT id, station_id, content, created_by, created_at, updated_at, deleted_at
FROM [dbo].[station_chat_announcements]
WHERE id = #{id, jdbcType=INTEGER}

mapper.update:
UPDATE [dbo].[station_chat_announcements]
SET content = #{content}, updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=INTEGER}

UPDATE [dbo].[station_chat_announcements]
SET deleted_at = #{deletedAt}
WHERE id = #{id, jdbcType=INTEGER}

mapper.select:
SELECT id, station_id, user_id, trip_plan_id, chat_type, content, created_at, deleted_at
FROM [dbo].[station_chat_messages]
WHERE id = #{id, jdbcType=INTEGER}

mapper.update:
UPDATE [dbo].[station_chat_messages]
SET deleted_at = #{deletedAt}
WHERE id = #{id, jdbcType=INTEGER}

mapper.select:
SELECT COUNT(1)
FROM [dbo].[station_chat_messages]
WHERE user_id = #{userId, jdbcType=INTEGER}
  AND created_at >= #{todayStart}
  AND deleted_at IS NULL
